}
if (this._checked) {
  var d1 = new Date(this._dateLimitedFrom), d2 = new Date(this._dateLimitedTo), e3 = $df.getResources(this._language, 'Message.RequiredField');
  a = ['ngay_mua', 'ngay_kh0', 'ngay_kh_kt', 'ngay_lct', 'ngay_dvsd', 'ngay_dc'];
  for (var i = 0; i < a.length; i++) {
    if (!this._checked) break;
