objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('dts')._controlBehavior, y = f.getItem('ats')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_nguyen_gia_nt,t_gt_da_kh_nt,t_gt_cl_nt,t_gt_kh_ky_nt,tien_cl_nt,nguyen_gia_vm_nt:t_nguyen_gia,t_gt_da_kh,t_gt_cl,t_gt_kh_ky,tien_cl,nguyen_gia_vm');
    v.addGridFields(g, 'nguyen_gia_nt,gt_da_kh_nt,gt_cl_nt,gt_kh_ky_nt,gt_da_kh00_nt:nguyen_gia,gt_da_kh,gt_cl,gt_kh_ky,gt_da_kh00');
    v.addTotalFields(g, [['t_nguyen_gia_nt', 'nguyen_gia_nt'], ['t_gt_da_kh_nt', 'gt_da_kh_nt'], ['t_gt_cl_nt', 'gt_cl_nt'], ['t_gt_kh_ky_nt', 'gt_kh_ky_nt'], ['t_nguyen_gia', 'nguyen_gia'], ['t_gt_da_kh', 'gt_da_kh'], ['t_gt_cl', 'gt_cl'], ['t_gt_kh_ky', 'gt_kh_ky']]);
    v.addGridFields(y, 'gia_tri_nt : gia_tri');
    v.set_referenceFields(null);
    v.set_executeExpression(['[tien_cl]:=[tien_cl_nt]*[ty_gia]']);
    v.set_executeExpression(['[nguyen_gia_vm]:=[nguyen_gia_vm_nt]*[ty_gia]']);
    v.init();
    v.setFormLayout(0);
    this.init(f);
  },
  onCurrencyChanged: function(sender, e) {
    this.onCurrencySelected(sender, e);
    var c = e.object, f = c._currency.parentForm;
    if (c._baseCurrency == e.type) {
      c._exchangeRate._controlBehavior._set_number(1);
      c.onExchangeRateChanged();
    }
    else {
      var d = f.getItemValue('ngay_lct');
      if (d) f.request('GetExchangeRate', 'GetExchangeRate', ['ma_nt', 'ngay_lct']);
    }
    set$Voucher$GridColumn(f, f.getItem('dts')._controlBehavior);
  },
  onDateChanged: function(sender, e) {
    var c = e.object, f = c._currency.parentForm;
    if (e.type && (c._currency.value != c._baseCurrency)) f.request('GetExchangeRate', 'DateChanged', ['ma_nt', 'ngay_lct']);
  },
  onCurrencySelected: function(sender, e) {if (e.object._baseCurrency == e.type) e.object._form.getItem('ma_bp').focus();}
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['dts','ats','ten_ts2'&ListTabChange;&PostTabChange;,'tien_cl_nt'],'');
  &PostTabFocus;
}

/* <flatten type="Javascript"> */
function on$Voucher$GridRender(sender, eventArgs) {
  var g = eventArgs.grid, f = g.get_element().parentForm, t = f.getItemValue('kieu_kh');
  if (t == 0) set$Voucher$GridValue(g, 'tab_yn', 1);
  set$Voucher$GridColumn(f, g);
}
function onChange$Voucher$DepreciationStartDate(o) {
  var f = o.parentForm, d = f.getItem('ngay_kh_kt');
  if (f.getItemValue('so_ky_kh') != 0) increaseDays(f, d);
    else f.setItemValue('ngay_kh_kt', null);
}
function onChange$Voucher$DepreciationPeriods(o) {
  var f = o.parentForm, d = f.getItem('ngay_kh_kt'), e = f.getItemValue('so_ky_kh');
  f.setItemValues('so_ky_kh_qd, so_ky_kh_cl', [e, e]);
  setDepreciationValue(d);
  if (o.value != 0) increaseDays(f, d);
    else f.setItemValue('ngay_kh_kt', null);
  f.live(f.getItem('ngay_kh_kt'));
}
function onChange$Voucher$DepreciationMethodSelectedIndex(o) {
  var f = o.parentForm, g = f.getItem("dts")._controlBehavior, d = f.getItem('ngay_kh_kt'), c = o.value, v = (c == 1 || c == 2);
  set$Voucher$GridValue(g, 'tab_yn', c == 0 ? 1 : 0);
  set$Voucher$GridColumn(f, g);
  set$Voucher$DependOnDepreciationMethod(f);
  g._setColumnReadOnly(g._getColumnOrder('gt_kh_ky_nt'), v);
  g._setColumnReadOnly(g._getColumnOrder('gt_kh_ky'), v);
  if (v) {
    setFocusWhenDepreciationMethodChange(f);
    f.setItemValue('t_gt_kh_ky_nt', 0);
    f.setItemValue('t_gt_kh_ky', 0);
  }
  setDepreciationValue(d);
}
function onChange$Voucher$RegulationDepreciationPeriods(o) {
  var f = o.parentForm;
  f.executeExpression(['[ty_le_kh_vm]:=[so_ky_kh] == 0 ? 0 : ([so_ky_kh_qd]/[so_ky_kh] - 1)*100']);
  f.live(f.getItem('ty_le_kh_vm'));
}
function onChange$Voucher$RoundItem(o) {
  var f = o.parentForm;
  f.executeExpression(['[tien_cl]:=[tien_cl_nt]*[ty_gia]']);
  f.live(f.getItem('tien_cl'));
}
function onChange$Voucher$ExceedingOriginalCost(o) {
  var f = o.parentForm;
  f.executeExpression(['[nguyen_gia_vm]:=[nguyen_gia_vm_nt]*[ty_gia]']);
  f.live(f.getItem('nguyen_gia_vm'));
}
/* </flatten> */


function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;
      &ListResponseTicket;

    case 'Suggestion':
      objectBehavior$Dir$Code.suggestion(f, result[0].Value);
      break;
    case 'Checking':
      objectBehavior$Dir$Code.checkCode(f);
      break;
    default:
      break;
  }
}

/* <flatten type="Javascript"> */
function on$Voucher$Error(f, errorMessage, c) {
  f._checked = false;
  $func.hideWait(f.get_id());
  $message.show(errorMessage, String.format('$find(\'{0}\').focus(\'{1}\');', f.get_id(), c));
}
function set$Voucher$GridColumn(f, g) {
  var t = (f.getItemValue('kieu_kh') == 2), c = f.getItemValue('ma_nt');
  g._setColumnVisible(g._getColumnOrder('gt_da_kh00_nt'), t);
  g._setColumnVisible(g._getColumnOrder('gt_da_kh00'), (t ? (c != f._baseCurrency) : false));
}
function set$Voucher$GridValue(g, c, v) {
  var column = g._getColumnOrder(c);
  for (var i = 0; i < g._rowCount; i++) {
    g._setItemValue(i + 1, column, v);
  }
}
function increaseDays(f, o) {
  var v = f.getItemValue('ngay_kh0', null, null, true), p = f.getItemValue('so_ky_kh'), n = 0;
  if (!v) return;
  if (f.$_method) {
    n = v.getDate();
    if (n > 28) {
     var k = (new Date(v.getFullYear(), v.getMonth() + p + 1, 0)).getDate();
     if (n > k) n = k;
    }
    n -= 1;
  }
  d = new Date(v.getFullYear(), v.getMonth() + p, n);
  o._controlBehavior.set_selectedDate(d);
}
function setDepreciationValue(o) {
  var f = o.parentForm; var g = f.getItem("dts")._controlBehavior;
  for (var i = 0; i < g._rowCount; i++) {
    g.assignExpression(i, '[gt_kh_ky_nt]:= [Rso_ky_kh] == 0 ? 0 : [nguyen_gia_nt]/[Rso_ky_kh]');
    g.assignExpression(i, '[gt_kh_ky]:= [Rso_ky_kh] == 0 ? 0 : [nguyen_gia]/[Rso_ky_kh]');
  }
  g.executeAggregate([['t_gt_kh_ky_nt', 'gt_kh_ky_nt'], ['t_gt_kh_ky', 'gt_kh_ky']]);
}
function set$Voucher$DependOnDepreciationMethod(f) {
  var c = f.getItemValue('kieu_kh');
  f.getItem('tong_sl').disabled = (c != 1);
  f.getItem('tl_kh00').disabled = f.getItem('ky_kh00').disabled = f.getItem('so_ky_kh_cl').disabled = (c != 2);
}
function setFocusWhenDepreciationMethodChange(f) {
  var c = f.getItemValue('kieu_kh');
  var n = (c != 0 && c == 1) ? 'tong_sl' : 'tl_kh00';
  var o = f.getItem(n);
  try {o.focus(); f.live(o);} catch (ex) {}
}
